import{bV as a,aL as i,u as e,G as t}from"./chunks/framework.BfzMay2U.js";const c=JSON.parse('{"title":"Portainer 的安装","description":"","frontmatter":{"title":"Portainer 的安装","date":"2023-02-05T16:12:10.000Z","categories":["Deploy"],"tags":["Portainer"]},"headers":[],"relativePath":"views/deploy/mac-docker-portainer-install.md","filePath":"views/deploy/mac-docker-portainer-install.md"}'),r={name:"views/deploy/mac-docker-portainer-install.md"};function n(p,s,l,o,h,d){return i(),e("div",null,[...s[0]||(s[0]=[t('<h1 id="portainer-的安装" tabindex="-1">Portainer 的安装 <a class="header-anchor" href="#portainer-的安装" aria-label="Permalink to &quot;Portainer 的安装&quot;">​</a></h1><p>官网：<a href="https://www.portainer.io" target="_blank" rel="noreferrer">https://www.portainer.io</a></p><p>文档地址：<a href="https://docs.portainer.io/v/ce-2.9/start/install/server/docker/linux" target="_blank" rel="noreferrer">https://docs.portainer.io/v/ce-2.9/start/install/server/docker/linux</a></p><h2 id="安装运行" tabindex="-1">安装运行 <a class="header-anchor" href="#安装运行" aria-label="Permalink to &quot;安装运行&quot;">​</a></h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 8000:8000</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 9000:9000</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> portainer</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --restart=always</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/run/docker.sock:/var/run/docker.sock</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> portainer_data:/data</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> portainer/portainer</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果本地有<code>php</code>，就会占据<code>9000</code>端口，需要另改一下映射端口。我本地有，所以改成</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 7678:8000</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 9093:9000</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> portainer</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --restart=always</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/run/docker.sock:/var/run/docker.sock</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /Users/wangxin/soft/portainer/data:/data</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> portainer/portainer</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>访问地址：本机<code>ip</code>加上端口<code>9093</code>，如果是上面的就是<code>9000</code></p><p>然后设置用户名和密码即可登录</p><blockquote><p>注意<code>-v</code>的<code>/var/run/docker.sock</code>是你本地运行的<code>docker</code>的<code>sock</code>地址，否则进进入之后无法显示对应的<code>local</code>环境，也就是本地环境</p></blockquote><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/images/image-20230205152909043.png" alt="image-20230205152909043" loading="lazy"></p><div class="danger custom-block"><p class="custom-block-title">危险</p><p>当然我这个图是比较失败的那种，没有显示出<code>Local</code>的环境选项</p></div>',12)])])}const F=a(r,[["render",n]]);export{c as __pageData,F as default};
